class Solution {
public:
    int hardestWorker(int n, vector<vector<int>>& logs) {
        vector<int> times(n, 0);
        for (auto& log : logs) {
            times[log[0]] += log[1];
        }
        int hardest = 0;
        for (int i = 1; i < n; ++i) {
            if (times[i] > times[hardest]) {
                hardest = i;
            }
        }
        return hardest;
    }
};
